		ORDER BY  F.SORG_NM , B.SSVC_LINE_TYPE_CD , D.SLVL_NM , E.SLVL_NM
	) A WHERE ROWNUM <= #{lastIndex}
)A WHERE RNUM >= #{firstIndex}

SELECT DISTINCT B.SSVC_LINE_TYPE_CD , C.SSVC_LINE_TYPE_NM , B.SSVC_GROUP_CD , D.SLVL_NM AS SSVC_GROUP_NM FROM MST.TB_OPER_TEAM_AUTH_TXN A ,MST.TB_LVL_BAS B ,MST.TB_SVC_LINE_TYPE_CD C ,MST.TB_LVL_CD D ,MST.TB_LVL_CD E WHERE 1=1 AND A.SPOS_DEPT_ORG_ID = #{sposDeptOrgId, jdbcType=CHAR}
AND B.SSVC_LINE_TYPE_CD = #{tbLvlBasVo.ssvcLineTypeCd, jdbcType=CHAR}
AND A.NLVL_BAS_SEQ = B.NLVL_BAS_SEQ AND B.SSVC_LINE_TYPE_CD = C.SSVC_LINE_TYPE_CD AND B.SSVC_GROUP_CD = D.SLVL_CD AND B.SSVC_OBJ_CD = E.SLVL_CD ORDER BY B.SSVC_GROUP_CD ASC

